### IMPORTANT
Only implement if model (or post-2025-10 variant) appears in embedding_candidates_2025_11+.json as eligible. Otherwise baseline-only.

## Purpose
Provide a static-embedding baseline and validate Matryoshka (MRL) truncation pipeline.
static-retrieval-mrl-en-v1 was reported as 397x faster than mpnet while supporting
MRL dimension truncation (768 → 256 → 128 → 64 with graceful quality degradation).

## Architecture
```rust
pub struct StaticMrlEmbedder {
    session: ort::Session,       // ONNX runtime session
    tokenizer: tokenizers::Tokenizer,
    native_dims: usize,          // 768 (full dimension)
    target_dims: Option<usize>,  // MRL truncation target (e.g., 256)
    name: String,
}

impl Embedder for StaticMrlEmbedder {
    fn embed_batch(&self, texts: &[&str]) -> Result<Vec<Vec<f32>>> {
        // 1. Tokenize all texts
        let encodings: Vec<_> = texts.iter()
            .map(|t| self.tokenizer.encode(*t, true))
            .collect::<Result<Vec<_>>>()?;

        // 2. Pad to max length in batch
        let max_len = encodings.iter().map(|e| e.len()).max().unwrap_or(0);
        let batch_size = encodings.len();

        // 3. Build input tensors
        let input_ids = build_padded_tensor(&encodings, max_len, 0);
        let attention_mask = build_attention_mask(&encodings, max_len);

        // 4. Run ONNX inference
        let outputs = self.session.run(ort::inputs![
            "input_ids" => input_ids,
            "attention_mask" => attention_mask,
        ]?)?;

        // 5. Extract embeddings (static model: single forward pass, fast)
        let embeddings_raw = outputs[0].extract_tensor::<f32>()?;

        // 6. Mean pool over token positions (respecting attention mask)
        let mut results = Vec::with_capacity(batch_size);
        for i in 0..batch_size {
            let mut pooled = mean_pool_with_mask(
                &embeddings_raw, i, max_len, self.native_dims, &attention_mask
            );

            // 7. MRL truncation if target_dims specified
            if let Some(target) = self.target_dims {
                pooled.truncate(target);
            }

            // 8. L2 normalize (must re-normalize after truncation!)
            l2_normalize(&mut pooled);
            results.push(pooled);
        }

        Ok(results)
    }

    fn dimensions(&self) -> usize {
        self.target_dims.unwrap_or(self.native_dims)
    }

    fn model_name(&self) -> &str { &self.name }

    fn supports_mrl(&self) -> bool { true }

    fn truncate(&self, embeddings: &[Vec<f32>], target_dim: usize) -> Result<Vec<Vec<f32>>> {
        assert!(target_dim <= self.native_dims, "Cannot expand beyond native dims");
        Ok(embeddings.iter().map(|emb| {
            let mut truncated: Vec<f32> = emb[..target_dim].to_vec();
            l2_normalize(&mut truncated);
            truncated
        }).collect())
    }
}
```

